LAYER
	NAME 'POL'
	TYPE POINT
	DUMP true
	TEMPLATE fooOnlyForWMSGetFeatureInfo 
	INCLUDE "datashare.inc"	
	DATA 'sp_geometry FROM vw_att_details_pole_map USING UNIQUE system_id USING srid=4326'	
	FILTER (%provinceFilter% AND (%layerFilter% ) AND (%prjectspecificationFilter% ) AND (%ownershipFilter% ) AND (%PODFilter% ) and (%NetworkFilter%)AND (%AutoPlanningNetworkFilter%))
			
	VALIDATION		
		'provinceFilter'   '.*'
		'layerFilter'   '.*'
		'prjectspecificationFilter'   '.*'
		'ownershipFilter'   '.*'							
		'PODFilter'   '.*'
		'NetworkFilter'   '.*'
		'AutoPlanningNetworkFilter' '.*'
	END 
	METADATA
		'ows_title' 'POLE'
	END
	STATUS OFF
	LABELITEM 'label_column'
	GROUP 'Network'		
									
	CLASS
		NAME 'Pole'
		EXPRESSION ('[specification]' ~* '7 M' AND '[network_status]'  eq 'P')
		STYLE
			SYMBOL "icons/Planned/Pole6.7.png"
			SIZE 30
			OFFSET 0 -5				
		END
		LEADER
		  GRIDSTEP 6
		  MAXDISTANCE 10000
		  STYLE
			COLOR 200 100 100
			WIDTH 1
		  END
		END
		LABEL 
			COLOR  255 0 0  		
			FONT "arial"
			TYPE truetype
			SIZE 8
			POSITION AUTO
			PARTIALS FALSE	
		END				
	END
	CLASS
		NAME 'Pole'
		EXPRESSION ('[specification]' ~* '7 M' AND '[network_status]'  eq 'A')  			
		STYLE
			SYMBOL "icons/AsBuild/Pole6.7.png"
			SIZE 20			
		END
		LEADER
		  GRIDSTEP 6
		  MAXDISTANCE 10000
		  STYLE
			COLOR 200 100 100
			WIDTH 1
		  END
		END
		LABEL 
			COLOR  255 0 0  		
			FONT "arial"
			TYPE truetype
			SIZE 8
			POSITION AUTO
			PARTIALS FALSE	
		END				
	END
	
